# Python 3.11+
"""Channel adapters ŌĆö the Adapter pattern.

Email, SMS, and push are three completely different external systems with three
different APIs (an SMTP-ish call, a telco REST call, a device push call). The
router must NOT know any of that. It only knows one shape: `adapter.send(event, pref)`.

Each concrete adapter wraps one disparate gateway behind that single interface.
This is the Adapter pattern: disparate providers, one uniform `ChannelAdapter.send`.
"""

from abc import ABC, abstractmethod

from models import (
    Channel,
    ChannelSendError,
    NotificationEvent,
    UserPreference,
)


# ŌöĆŌöĆ WHY THIS INTERFACE ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# The single shape the router talks to. Every channel ŌĆö email, SMS, push ŌĆö looks
# identical from the router's side: it has a channel() identity and a send().
# Adding a 4th channel (WhatsApp) is a new class here, zero router changes.
# ­¤ÄÖ’ĖÅ "ChannelAdapter is the one interface the router speaks. It doesn't know if
#     it's emailing or texting ŌĆö it just calls send. That's the Adapter seam."
class ChannelAdapter(ABC):
    @abstractmethod
    def channel(self) -> Channel:
        """Which channel this adapter serves (its identity in the registry)."""

    @abstractmethod
    def send(self, event: NotificationEvent, pref: UserPreference) -> None:
        """Deliver the event on this channel. Raise ChannelSendError on hard failure."""


# ŌöĆŌöĆ WHY THESE FAKE GATEWAYS ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# In production these would be real SDK clients (an email provider, a telco SMS
# API, FCM/APNs for push). For an in-memory design we model each as a tiny object
# that records what it was asked to send, so a test can assert "the SMS gateway
# received notification n-1 exactly once".
# ­¤ÄÖ’ĖÅ "These three fakes stand in for the real providers. Each just records the
#     ids it was told to send, so my concurrency test can prove at-most-once."
class RecordingGateway:
    """A stand-in for one real external provider; records every send call."""

    def __init__(self, name: str) -> None:
        self.name = name
        self.sent_ids: list[str] = []

    def transmit(self, notification_id: str, to: str, body: str) -> None:
        # WHY: just append ŌĆö the test inspects sent_ids to count deliveries. In
        #      production this would be the real network call to the provider.
        self.sent_ids.append(notification_id)


class EmailChannelAdapter(ChannelAdapter):
    """Adapts the email provider to the ChannelAdapter interface."""

    def __init__(self, gateway: RecordingGateway) -> None:
        self._gateway = gateway

    def channel(self) -> Channel:
        return Channel.EMAIL

    def send(self, event: NotificationEvent, pref: UserPreference) -> None:
        # WHY: the adapter is responsible for translating the uniform call into the
        #      provider's own arguments. No email address means we cannot send.
        if pref.email is None:
            raise ChannelSendError(f"user {pref.user_id} has no email on file")
        body = f"[{event.event_type.value}] {event.payload.get('text', '')}"
        self._gateway.transmit(event.notification_id, pref.email, body)


class SmsChannelAdapter(ChannelAdapter):
    """Adapts the SMS provider to the ChannelAdapter interface."""

    def __init__(self, gateway: RecordingGateway) -> None:
        self._gateway = gateway

    def channel(self) -> Channel:
        return Channel.SMS

    def send(self, event: NotificationEvent, pref: UserPreference) -> None:
        if pref.phone is None:
            raise ChannelSendError(f"user {pref.user_id} has no phone on file")
        body = event.payload.get("text", event.event_type.value)
        self._gateway.transmit(event.notification_id, pref.phone, body)


class PushChannelAdapter(ChannelAdapter):
    """Adapts the push provider (FCM/APNs) to the ChannelAdapter interface."""

    def __init__(self, gateway: RecordingGateway) -> None:
        self._gateway = gateway

    def channel(self) -> Channel:
        return Channel.PUSH

    def send(self, event: NotificationEvent, pref: UserPreference) -> None:
        if pref.device_token is None:
            raise ChannelSendError(f"user {pref.user_id} has no device token on file")
        body = event.payload.get("text", event.event_type.value)
        self._gateway.transmit(event.notification_id, pref.device_token, body)
